import type { Meta, StoryObj } from '@storybook/react-vite';
import { Tooltip } from './Tooltip';
import { Button } from '../Button';
import { Space } from '../Space';

const triggerButton = <Button>Hover me</Button>;

const placements = [
  'top',
  'top-start',
  'top-end',
  'bottom',
  'bottom-start',
  'bottom-end',
  'left',
  'right',
] as const;

const meta = {
  title: 'Components/Tooltip',
  component: Tooltip,
  tags: ['autodocs'],
  argTypes: {
    content: { control: 'text' },
    placement: { control: 'select', options: placements },
    trigger: { control: 'inline-radio', options: ['hover', 'click', 'focus'] },
    effect: { control: 'inline-radio', options: ['dark', 'light'] },
    showArrow: { control: 'boolean' },
    offset: { control: 'number' },
    disabled: { control: 'boolean' },
    open: { control: false },
    defaultOpen: { control: false },
    onOpenChange: { control: false },
    children: { control: false },
  },
  args: {
    content: 'Helpful hint',
    placement: 'top',
    trigger: 'hover',
    effect: 'dark',
    // Satisfies the required `children` prop; stories override it via `render`.
    children: triggerButton,
  },
} satisfies Meta<typeof Tooltip>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {
  render: (args) => (
    <Tooltip {...args}>
      <Button>Hover me</Button>
    </Tooltip>
  ),
};

export const Placements: Story = {
  render: () => (
    <Space wrap>
      <Tooltip content="Top" placement="top">
        <Button>Top</Button>
      </Tooltip>
      <Tooltip content="Bottom" placement="bottom">
        <Button>Bottom</Button>
      </Tooltip>
      <Tooltip content="Left" placement="left">
        <Button>Left</Button>
      </Tooltip>
      <Tooltip content="Right" placement="right">
        <Button>Right</Button>
      </Tooltip>
    </Space>
  ),
};

export const Effects: Story = {
  name: 'Dark and light',
  render: () => (
    <Space wrap>
      <Tooltip content="Dark surface" effect="dark">
        <Button>Dark</Button>
      </Tooltip>
      <Tooltip content="Light surface" effect="light">
        <Button>Light</Button>
      </Tooltip>
    </Space>
  ),
};

export const Triggers: Story = {
  render: () => (
    <Space wrap>
      <Tooltip content="Opens on hover" trigger="hover">
        <Button>Hover</Button>
      </Tooltip>
      <Tooltip content="Opens on click" trigger="click">
        <Button>Click</Button>
      </Tooltip>
      <Tooltip content="Opens on focus" trigger="focus">
        <Button>Focus</Button>
      </Tooltip>
    </Space>
  ),
};

import {
  cloneElement,
  forwardRef,
  isValidElement,
  type ReactElement,
  type ReactNode,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type Placement, Popper } from '../Overlay';

export type TooltipTrigger = 'hover' | 'click' | 'focus';
export type TooltipEffect = 'dark' | 'light';

export interface TooltipProps {
  /** Tooltip content. */
  content: ReactNode;
  /** Placement of the tooltip relative to the trigger. */
  placement?: Placement;
  /** How the tooltip opens. */
  trigger?: TooltipTrigger;
  /** Disable the tooltip; the trigger renders without one. */
  disabled?: boolean;
  /** Visual theme of the tooltip surface. */
  effect?: TooltipEffect;
  /** Show the arrow pointing at the trigger. */
  showArrow?: boolean;
  /** Gap between the trigger and the tooltip, in px. */
  offset?: number;
  /** Controlled open state. */
  open?: boolean;
  /** Initial open state when uncontrolled. */
  defaultOpen?: boolean;
  /** Fired when the open state changes. */
  onOpenChange?: (open: boolean) => void;
  /** Trigger element. */
  children: ReactElement;
}

export const Tooltip = forwardRef<HTMLDivElement, TooltipProps>(function Tooltip(props, ref) {
  const {
    content,
    placement = 'top',
    trigger = 'hover',
    disabled = false,
    effect = 'dark',
    showArrow = true,
    offset = 8,
    open,
    defaultOpen,
    onOpenChange,
    children,
  } = props;

  const ns = useNamespace('tooltip');

  if (!isValidElement(children)) {
    return <>{children}</>;
  }

  // Hold the user-provided ref on the trigger; Popper merges in its own.
  const reference = ref ? cloneElement(children, { ref } as Record<string, unknown>) : children;

  return (
    <Popper
      reference={reference}
      trigger={trigger}
      placement={placement}
      offset={offset}
      role="tooltip"
      showArrow={showArrow}
      disabled={disabled || content == null || content === ''}
      popperClass={cls(ns.b(), ns.m(effect))}
      open={open}
      defaultOpen={defaultOpen}
      onOpenChange={onOpenChange}
    >
      <div className={ns.e('content')}>{content}</div>
    </Popper>
  );
});

.ec-tooltip {
  --ec-tooltip-padding: 6px 11px;
  --ec-tooltip-font-size: var(--ec-font-size-small);

  box-sizing: border-box;
  max-width: 280px;
  padding: var(--ec-tooltip-padding);
  font-size: var(--ec-tooltip-font-size);
  line-height: 1.4;
}

.ec-tooltip__content {
  box-sizing: border-box;
}

/* ---- Light effect: the default popper surface ---- */
.ec-tooltip--light {
  background-color: var(--ec-bg-color-overlay);
  border: 1px solid var(--ec-border-color-light);
  color: var(--ec-text-color-regular);
}

/* ---- Dark effect: dark surface, light text ---- */
.ec-tooltip--dark {
  background-color: var(--ec-text-color-primary);
  border: 1px solid var(--ec-text-color-primary);
  color: var(--ec-bg-color-overlay);
}

.ec-tooltip--dark .ec-popper__arrow {
  background-color: var(--ec-text-color-primary);
  border-color: var(--ec-text-color-primary);
}
